% \prod_{v \in \V(\Gamma_\delta)} \exp\left(-\frac12 \eta(v) \right)
% \\ \hspace{+10pt}
% \prod_{e=(h,h')\in \E(\Gamma_\delta)}
% \frac{1-\exp\left(-\frac{w(h)w(h')}2(\psi_h+\psi_{h'})\right)}{\psi_h + \psi_{h'}} \Bigg]\, ."
